class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        vector<int> partner(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            partner[i] = (i % 2 == 0) ? i + 1 : i - 1;
        }
        vector<int> parent(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            parent[i] = i;
        }
        for (int i = 0; i < 2 * n; i += 2) {
            unionSet(parent, row[i], row[i + 1]);
        }
        int count = 0;
        for (int i = 0; i < 2 * n; i += 2) {
            if (findSet(parent, i) != findSet(parent, partner[i])) {
                count++;
                unionSet(parent, i, partner[i]);
            }
        }
        return count;
    }

    int findSet(vector<int>& parent, int x) {
        if (parent[x] != x) {
            parent[x] = findSet(parent, parent[x]);
        }
        return parent[x];
    }

    void unionSet(vector<int>& parent, int x, int y) {
        int rootX = findSet(parent, x);
        int rootY = findSet(parent, y);
        if (rootX != rootY) {
            parent[rootX] = rootY;
        }
    }
};
